import React, { useState } from 'react';
import main_page from '../css/main_page.css'

import Header from './components/Header';
import LeftMenu from './components/LeftMenu';
import DashboardContent from './components/DashboardContent';

const MainPage = () => {
    // 2. Стан для відстеження активного пункту меню
    const [activeMenuItem, setActiveMenuItem] = useState('dashboard');

    // 3. Функція, яка викликається при натисканні на пункт меню
    const handleMenuItemClick = (key) => {
        setActiveMenuItem(key);
        // Тут можна додати логіку для зміни вмісту сторінки або навігації
        console.log(`Навігація до: ${key}`);
    };
    
    // 4. Функція для виходу (placeholder)
    const handleLogout = () => {
        console.log('Користувач вийшов!');
        // Тут має бути логіка виходу та перенаправлення на сторінку логіну
    };

  return (
      <>
          <Header /> 
          <div className={main_page.main_page}>
            <LeftMenu 
                activeItem={activeMenuItem}
                onMenuItemClick={handleMenuItemClick}
                onLogout={handleLogout}
            />
            
            <DashboardContent/>
          </div>
      </>
  );
};

export default MainPage;
